root_vars:
/* Accent System — gold primary (BLDC component tone) */
--gold-bright: #fbbf24;
--gold-deep: #d97706;
--gold-line: rgba(245, 158, 11, 0.18);

/* Secondary accents */
--blue: #3b82f6;
--blue-glow: rgba(59, 130, 246, 0.30);
--violet: #8b5cf6;
--violet-glow: rgba(139, 92, 246, 0.30);
--green: #10b981;
--green-glow: rgba(16, 185, 129, 0.30);
--rose: #f43f5e;
--rose-glow: rgba(244, 63, 94, 0.30);

/* Background system (light theme) */
--bg-base: #f5f5f7;
--bg-deep: #ebebef;
--bg-overlay: rgba(255, 255, 255, 0.72);

/* Text */
--text-primary: #1a1a2e;
--text-secondary: #4a4a68;
--text-tertiary: #80809a;
--text-on-gold: #ffffff;

/* Borders */
--border-soft: rgba(26, 26, 46, 0.06);
--border-medium: rgba(26, 26, 46, 0.12);
--border-glass: rgba(255, 255, 255, 0.9);

/* 4-Layer Shadow System (AsIDE-grade) */
--shadow-glass:
  0 1px 0 rgba(255, 255, 255, 1) inset,
  0 4px 16px rgba(26, 26, 46, 0.04),
  0 12px 40px rgba(26, 26, 46, 0.07),
  0 24px 64px rgba(26, 26, 46, 0.05);
--shadow-glass-hover:
  0 1px 0 rgba(255, 255, 255, 1) inset,
  0 6px 20px rgba(26, 26, 46, 0.06),
  0 16px 48px rgba(26, 26, 46, 0.10),
  0 32px 80px rgba(26, 26, 46, 0.07);
--shadow-gold-glow:
  0 1px 0 rgba(255, 255, 255, 0.4) inset,
  0 4px 14px var(--gold-glow),
  0 12px 28px rgba(245, 158, 11, 0.18);
--shadow-deep: 0 1px 0 rgba(255, 255, 255, 0.9) inset, 0 20px 60px rgba(26, 26, 46, 0.12), 0 40px 120px rgba(26, 26, 46, 0.08);

/* Motion (spring physics) */
--ease-smooth: cubic-bezier(0.4, 0, 0.2, 1);
--ease-soft: cubic-bezier(0.22, 1, 0.36, 1);
--dur-fast: 180ms;
--dur: 320ms;
--dur-slow: 580ms;

/* Radius hierarchy */
--r-xl: 28px;
--r-lg: 20px;
--r-md: 14px;
--r-sm: 10px;
--r-pill: 999px;

/* Typography scale */
--fs-display: 38px;
--fs-h1: 28px;
--fs-h2: 22px;
--fs-h3: 18px;
--fs-body: 14px;
--fs-micro: 10px;

/* Spacing scale */
--sp-1: 4px;
--sp-2: 8px;
--sp-3: 12px;
--sp-4: 16px;
--sp-5: 24px;
--sp-6: 32px;
--sp-8: 48px;

/* Fonts */
--font-mono: "JetBrains Mono", "SF Mono", Menlo, monospace;

--shadow-fast: 0 1px 2px rgba(15, 15, 30, 0.06), 0 0 0 1px rgba(15, 15, 30, 0.04);
--shadow-mid: 0 4px 12px rgba(15, 15, 30, 0.08), 0 0 0 1px rgba(15, 15, 30, 0.06);
--shadow-deep: 0 1px 0 rgba(255, 255, 255, 0.9) inset, 0 20px 60px rgba(26, 26, 46, 0.12), 0 40px 120px rgba(26, 26, 46, 0.08);
--shadow-glow-gold: 0 0 0 1px var(--gold-line), 0 4px 24px rgba(245, 158, 11, 0.18);
--shadow-glass-inset: inset 0 1px 0 rgba(255, 255, 255, 0.6), inset 0 -1px 0 rgba(15, 15, 30, 0.04);
